const input = $input.first().json.body || $input.first().json;

// VRF — GUARD + VALIDATE
const chat_id = parseInt(input.chat_id);
const provider_id = parseInt(input.provider_id);
const service_id = parseInt(input.service_id);
const start_time = input.start_time;
const user_email = input.user_email || '';
const user_name = input.user_name || 'Paciente';

if (!chat_id || !provider_id || !service_id || !start_time) {
  throw new Error('Missing required fields: chat_id, provider_id, service_id, start_time');
}

return [{
  json: {
    chat_id,
    provider_id,
    service_id,
    start_time,
    user_email,
    user_name
  }
}];

const dalResponse = $input.first()?.json || {};
const isSuccess = dalResponse.success === true;

return [{
  json: {
    success: isSuccess,
    error_code: isSuccess ? null : (dalResponse.error_code || 'DAL_ERROR'),
    error_message: isSuccess ? null : (dalResponse.error_message || dalResponse.message || 'Booking creation failed'),
    data: isSuccess ? (dalResponse.data || dalResponse) : null,
    _meta: {
      source: 'DB_Create_Booking',
      timestamp: new Date().toISOString(),
      workflow_id: 'DB_Create_Booking',
      version: '1.1.0'
    }
  }
}];

